COMPILER_SOURCE["util.c"] =
  "/* ================================================================\n" +
  " * Error reporting\n" +
  " * ================================================================ */\n" +
  "\n" +
  "void error(int line, int col, char *msg) {\n" +
  "    printf(\"%d:%d: error: %s\\n\", line, col, msg);\n" +
  "    exit(1);\n" +
  "}\n" +
  "\n" +
  "char *strdupn(char *s, int maxlen) {\n" +
  "    char *dst;\n" +
  "    dst = (char *)malloc(maxlen + 1);\n" +
  "    strncpy(dst, s, maxlen);\n" +
  "    dst[maxlen] = '\\0';\n" +
  "    return dst;\n" +
  "}\n" +
  "\n" +
  "/* Build mangled name: __static_{func}_{var} */\n" +
  "char *mangle_static(char *func, char *var) {\n" +
  "    char *r;\n" +
  "    int fl;\n" +
  "    int vl;\n" +
  "    int i;\n" +
  "    int j;\n" +
  "    fl = 0;\n" +
  "    while (func[fl]) fl++;\n" +
  "    vl = 0;\n" +
  "    while (var[vl]) vl++;\n" +
  "    r = (char *)malloc(9 + fl + 1 + vl + 1);\n" +
  "    j = 0;\n" +
  "    r[j] = '_'; j++;\n" +
  "    r[j] = '_'; j++;\n" +
  "    r[j] = 's'; j++;\n" +
  "    r[j] = 't'; j++;\n" +
  "    r[j] = 'a'; j++;\n" +
  "    r[j] = 't'; j++;\n" +
  "    r[j] = 'i'; j++;\n" +
  "    r[j] = 'c'; j++;\n" +
  "    r[j] = '_'; j++;\n" +
  "    for (i = 0; i < fl; i++) { r[j] = func[i]; j++; }\n" +
  "    r[j] = '_'; j++;\n" +
  "    for (i = 0; i < vl; i++) { r[j] = var[i]; j++; }\n" +
  "    r[j] = 0;\n" +
  "    return r;\n" +
  "}\n" +
  "\n" +
  "";

COMPILER_SOURCE["source.c"] =
  "/* ================================================================\n" +
  " * Source buffer — read entire stdin via getchar loop\n" +
  " * ================================================================ */\n" +
  "\n" +
  "char *src;\n" +
  "int src_len;\n" +
  "\n" +
  "void read_source(void) {\n" +
  "    int c;\n" +
  "    int cap;\n" +
  "    src = (char *)malloc(MAX_SRC);\n" +
  "    src_len = 0;\n" +
  "    cap = MAX_SRC;\n" +
  "    c = getchar();\n" +
  "    while (c != -1) {\n" +
  "        if (src_len >= cap - 1) {\n" +
  "            break;\n" +
  "        }\n" +
  "        src[src_len] = (char)c;\n" +
  "        src_len++;\n" +
  "        c = getchar();\n" +
  "    }\n" +
  "    src[src_len] = '\\0';\n" +
  "}\n" +
  "\n" +
  "";

