  "        out(\"  (if (i32.eqz (local.get $val))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (then\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (i32.store8 (local.get $buf) (i32.const 48))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (return (i32.add (local.get $buf) (i32.const 1)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    )\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  )\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (local.set $shift (i32.const 28))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (block $done (loop $nibbles\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (br_if $done (i32.lt_s (local.get $shift) (i32.const 0)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (local.set $nib (i32.and (i32.shr_u (local.get $val) (local.get $shift)) (i32.const 15)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (if (i32.or (local.get $started) (i32.ne (local.get $nib) (i32.const 0)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (then\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"        (local.set $started (i32.const 1))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"        (if (i32.lt_u (local.get $nib) (i32.const 10))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"          (then (i32.store8 (local.get $buf) (i32.add (i32.const 48) (local.get $nib))))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"          (else (i32.store8 (local.get $buf) (i32.add (i32.const 87) (local.get $nib))))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"        )\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"        (local.set $buf (i32.add (local.get $buf) (i32.const 1)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      )\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    )\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (local.set $shift (i32.sub (local.get $shift) (i32.const 4)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (br $nibbles)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  ))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (local.get $buf)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\")\\n\");\n" +
  "    }\n" +
  "\n" +
  "    /* optional runtime: qsort (only emitted if used) */\n" +
  "    if (uses_qsort) {\n" +
  "        emit_indent();\n" +
  "        out(\"(func $qsort (param $base i32) (param $nmemb i32) (param $size i32) (param $compar i32)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (local $i i32) (local $j i32) (local $pi i32) (local $pj i32) (local $tmp i32)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (local.set $i (i32.const 1))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (block $outer_done (loop $outer\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (br_if $outer_done (i32.ge_u (local.get $i) (local.get $nmemb)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (local.set $j (local.get $i))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (block $inner_done (loop $inner\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (br_if $inner_done (i32.le_s (local.get $j) (i32.const 0)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (local.set $pj (i32.add (local.get $base) (i32.mul (local.get $j) (local.get $size))))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (local.set $pi (i32.sub (local.get $pj) (local.get $size)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (br_if $inner_done (i32.le_s\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"        (call_indirect (type $__fntype_2_i32) (local.get $pi) (local.get $pj) (local.get $compar))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"        (i32.const 0)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (local.set $tmp (i32.load (local.get $pi)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (i32.store (local.get $pi) (i32.load (local.get $pj)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (i32.store (local.get $pj) (local.get $tmp))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (local.set $j (i32.sub (local.get $j) (i32.const 1)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (br $inner)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    ))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (local.set $i (i32.add (local.get $i) (i32.const 1)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (br $outer)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  ))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\")\\n\");\n" +
  "    }\n" +
  "\n" +
  "    /* optional runtime: bsearch (only emitted if used) */\n" +
  "    if (uses_bsearch) {\n" +
  "        emit_indent();\n" +
  "        out(\"(func $bsearch (param $key i32) (param $base i32) (param $nmemb i32) (param $size i32) (param $compar i32) (result i32)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (local $lo i32) (local $hi i32) (local $mid i32) (local $p i32) (local $cmp i32)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (local.set $lo (i32.const 0))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (local.set $hi (local.get $nmemb))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (block $done (loop $search\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (br_if $done (i32.ge_u (local.get $lo) (local.get $hi)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (local.set $mid (i32.shr_u (i32.add (local.get $lo) (local.get $hi)) (i32.const 1)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (local.set $p (i32.add (local.get $base) (i32.mul (local.get $mid) (local.get $size))))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (local.set $cmp (call_indirect (type $__fntype_2_i32) (local.get $key) (local.get $p) (local.get $compar)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (if (i32.eqz (local.get $cmp))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (then (return (local.get $p)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    )\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (if (i32.lt_s (local.get $cmp) (i32.const 0))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (then (local.set $hi (local.get $mid)))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"      (else (local.set $lo (i32.add (local.get $mid) (i32.const 1))))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    )\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"    (br $search)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  ))\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"  (i32.const 0)\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\")\\n\");\n" +
  "    }\n" +
  "\n" +
  "    emit_indent();\n" +
  "    out(\"\\n\");\n" +
  "\n" +
  "    /* _start — calls __init if needed, then main */\n" +
  "    {\n" +
  "        int need_init;\n" +
  "        int gi2;\n" +
  "        need_init = 0;\n" +
  "        for (gi2 = 0; gi2 < nglobals; gi2++) {\n" +
  "            if (globals_tbl[gi2]->gv_arr_len > 0 && globals_tbl[gi2]->gv_arr_str_ids != (int *)0) {\n" +
  "                need_init = 1;\n" +
  "            }\n" +
  "        }\n" +
  "        if (need_init) {\n" +
  "            emit_indent();\n" +
  "            out(\"(func $__init\\n\");\n" +
  "            indent_level++;\n" +
  "            emit_indent();\n" +
  "            out(\"(local $__ptr i32)\\n\");\n" +
  "            for (gi2 = 0; gi2 < nglobals; gi2++) {\n" +
  "                if (globals_tbl[gi2]->gv_arr_len > 0 && globals_tbl[gi2]->gv_arr_str_ids != (int *)0) {\n" +
  "                    int ai2;\n" +
  "                    /* allocate arr_len * 4 bytes */\n" +
  "                    emit_indent();\n" +
  "                    out(\"i32.const \"); out_d(globals_tbl[gi2]->gv_arr_len * 4); out(\"\\n\");\n" +
  "                    emit_indent();\n" +
  "                    out(\"call $malloc\\n\");\n" +
  "                    emit_indent();\n" +
  "                    out(\"local.tee $__ptr\\n\");\n" +
  "                    emit_indent();\n" +
  "                    out(\"global.set $\"); out(globals_tbl[gi2]->name); out(\"\\n\");\n" +
  "                    /* store each element */\n" +
  "                    for (ai2 = 0; ai2 < globals_tbl[gi2]->gv_arr_len; ai2++) {\n" +
  "                        emit_indent();\n" +
  "                        out(\"local.get $__ptr\\n\");\n" +
  "                        if (ai2 > 0) {\n" +
  "                            emit_indent();\n" +
  "                            out(\"i32.const \"); out_d(ai2 * 4); out(\"\\n\");\n" +
  "                            emit_indent();\n" +
  "                            out(\"i32.add\\n\");\n" +
  "                        }\n" +
  "                        emit_indent();\n" +
  "                        out(\"i32.const \"); out_d(str_table[globals_tbl[gi2]->gv_arr_str_ids[ai2]]->offset); out(\"\\n\");\n" +
  "                        emit_indent();\n" +
  "                        out(\"i32.store\\n\");\n" +
  "                    }\n" +
  "                }\n" +
  "            }\n" +
  "            indent_level--;\n" +
  "            emit_indent();\n" +
  "            out(\")\\n\");\n" +
  "        }\n" +
  "        emit_indent();\n" +
  "        out(\"(func $_start (export \\\"_start\\\")\\n\");\n" +
  "        indent_level++;\n" +
  "        if (need_init) {\n" +
  "            emit_indent();\n" +
  "            out(\"call $__init\\n\");\n" +
  "        }\n" +
  "        emit_indent();\n" +
  "        out(\"call $main\\n\");\n" +
  "        emit_indent();\n" +
  "        out(\"call $__proc_exit\\n\");\n" +
  "        indent_level--;\n" +
  "        emit_indent();\n" +
  "        out(\")\\n\");\n" +
  "    }\n" +
  "\n" +
  "    indent_level--;\n" +
  "    emit_indent();\n" +
  "    out(\")\\n\");\n" +
  "}\n" +
  "\n" +
  "";

COMPILER_SOURCE["assembler.h"] =
  "/* assembler.h — WAT text to WASM binary assembler */\n" +
  "\n" +
  "void assemble_wat(struct ByteVec *input);\n" +
  "void assemble_wat_to_bv(struct ByteVec *input, struct ByteVec *output);\n" +
  "";

COMPILER_SOURCE["assembler.c"] =
  "/* assembler.c — WAT text to WASM binary assembler */\n" +
  "\n" +
  "/* ================================================================\n" +
  " * WAT Token Types\n" +
  " * ================================================================ */\n" +
  "\n" +
  "#define WTOK_LPAREN  1\n" +
  "#define WTOK_RPAREN  2\n" +
  "#define WTOK_KW      3\n" +
  "#define WTOK_NAME    4\n" +
  "#define WTOK_INT     5\n" +
  "#define WTOK_FLOAT   6\n" +
  "#define WTOK_STRING  7\n" +
  "#define WTOK_EOF     8\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Assembler Limits\n" +
  " * ================================================================ */\n" +
  "\n" +
  "#define ASM_MAX_TYPES    128\n" +
  "#define ASM_MAX_FUNCS    512\n" +
  "#define ASM_MAX_GLOBALS  256\n" +
  "#define ASM_MAX_DATA     2048\n" +
  "#define ASM_MAX_LOCALS   512\n" +
  "#define ASM_MAX_LABELS   64\n" +
  "#define ASM_MAX_TYPE_NAMES 64\n" +
  "#define ASM_MAX_ELEM     256\n" +
  "#define ASM_MAX_PARAMS   16\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Tokenizer State\n" +
  " * ================================================================ */\n" +
  "\n" +
  "char *asm_src;\n" +
  "int asm_src_len;\n" +
  "int asm_pos;\n" +
  "int asm_tok;\n" +
  "char *asm_tok_str;\n" +
  "int asm_tok_int;\n" +
  "\n" +
  "/* Memory instruction offset (parsed from offset=N tokens) */\n" +
  "int asm_mem_offset;\n" +
  "\n" +
  "/* Save/restore for lookahead */\n" +
  "int asm_saved_pos;\n" +
  "int asm_saved_tok;\n" +
  "char *asm_saved_str;\n" +
  "int asm_saved_int;\n" +
  "\n" +
  "void asm_error(char *msg) {\n" +
  "    printf(\"assembler error: %s\\n\", msg);\n" +
  "    exit(1);\n" +
  "}\n" +
  "\n" +
  "void asm_save(void) {\n" +
  "    asm_saved_pos = asm_pos;\n" +
  "    asm_saved_tok = asm_tok;\n" +
  "    asm_saved_str = asm_tok_str;\n" +
  "    asm_saved_int = asm_tok_int;\n" +
  "}\n" +
  "\n" +
  "void asm_restore(void) {\n" +
  "    asm_pos = asm_saved_pos;\n" +
  "    asm_tok = asm_saved_tok;\n" +
  "    asm_tok_str = asm_saved_str;\n" +
  "    asm_tok_int = asm_saved_int;\n" +
  "}\n" +
  "\n" +
  "void asm_skip_ws(void) {\n" +
  "    int c;\n" +
  "    while (asm_pos < asm_src_len) {\n" +
  "        c = asm_src[asm_pos] & 0xFF;\n" +
  "        if (c == ' ' || c == '\\t' || c == '\\n' || c == '\\r') {\n" +
  "            asm_pos++;\n" +
  "        } else if (c == ';' && asm_pos + 1 < asm_src_len && (asm_src[asm_pos + 1] & 0xFF) == ';') {\n" +
  "            while (asm_pos < asm_src_len && (asm_src[asm_pos] & 0xFF) != '\\n') asm_pos++;\n" +
  "        } else {\n" +
  "            break;\n" +
  "        }\n" +
  "    }\n" +
  "}\n" +
  "\n" +
  "void asm_next(void) {\n" +
  "    int c;\n" +
  "    int start;\n" +
  "    int len;\n" +
  "    int is_float;\n" +
  "    int p;\n" +
  "    int sign;\n" +
  "    asm_skip_ws();\n" +
  "    if (asm_pos >= asm_src_len) { asm_tok = WTOK_EOF; return; }\n" +
  "    c = asm_src[asm_pos] & 0xFF;\n" +
  "\n" +
  "    if (c == '(') { asm_tok = WTOK_LPAREN; asm_pos++; return; }\n" +
  "    if (c == ')') { asm_tok = WTOK_RPAREN; asm_pos++; return; }\n" +
  "\n" +
  "    /* String literal */\n" +
  "    if (c == '\"') {\n" +
  "        asm_pos++;\n" +
  "        start = asm_pos;\n" +
  "        while (asm_pos < asm_src_len && (asm_src[asm_pos] & 0xFF) != '\"') {\n" +
  "            if ((asm_src[asm_pos] & 0xFF) == '\\\\') asm_pos++;\n" +
  "            asm_pos++;\n" +
  "        }\n" +
  "        len = asm_pos - start;\n" +
  "        asm_tok_str = strdupn(asm_src + start, len);\n" +
  "        asm_tok = WTOK_STRING;\n" +
  "        if (asm_pos < asm_src_len) asm_pos++;\n" +
  "        return;\n" +
  "    }\n" +
  "\n" +
  "    /* $name */\n" +
  "    if (c == '$') {\n" +
  "        asm_pos++;\n" +
  "        start = asm_pos;\n" +
  "        while (asm_pos < asm_src_len) {\n" +
  "            c = asm_src[asm_pos] & 0xFF;\n" +
  "            if (c == ' ' || c == '\\t' || c == '\\n' || c == '\\r' ||\n" +
  "                c == '(' || c == ')') break;\n" +
  "            asm_pos++;\n" +
  "        }\n" +
  "        len = asm_pos - start;\n" +
  "        asm_tok_str = strdupn(asm_src + start, len);\n" +
  "        asm_tok = WTOK_NAME;\n" +
  "        return;\n" +
  "    }\n" +
  "\n" +
  "    /* Number: starts with digit or '-' followed by digit */\n" +
  "    {\n" +
  "    int is_number;\n" +
  "    is_number = 0;\n" +
  "    if (c >= '0' && c <= '9') {\n" +
  "        is_number = 1;\n" +
  "    } else if (c == '-' && asm_pos + 1 < asm_src_len) {\n" +
  "        int nc;\n" +
  "        nc = asm_src[asm_pos + 1] & 0xFF;\n" +
  "        if (nc >= '0' && nc <= '9') {\n" +
  "            is_number = 1;\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    if (is_number) {\n" +
  "        /* Number parsing */\n" +
  "        start = asm_pos;\n" +
  "        is_float = 0;\n" +
  "        if ((asm_src[asm_pos] & 0xFF) == '-') asm_pos++;\n" +
  "\n" +
  "        /* Check for hex 0x */\n" +
  "        if (asm_pos < asm_src_len && (asm_src[asm_pos] & 0xFF) == '0' &&\n" +
  "            asm_pos + 1 < asm_src_len && (asm_src[asm_pos + 1] & 0xFF) == 'x') {\n" +
  "            asm_pos = asm_pos + 2;\n" +
  "            asm_tok_int = 0;\n" +
  "            while (asm_pos < asm_src_len) {\n" +
  "                c = asm_src[asm_pos] & 0xFF;\n" +
  "                if (c >= '0' && c <= '9') { asm_tok_int = asm_tok_int * 16 + (c - '0'); asm_pos++; }\n" +
  "                else if (c >= 'a' && c <= 'f') { asm_tok_int = asm_tok_int * 16 + 10 + (c - 'a'); asm_pos++; }\n" +
  "                else if (c >= 'A' && c <= 'F') { asm_tok_int = asm_tok_int * 16 + 10 + (c - 'A'); asm_pos++; }\n" +
  "                else break;\n" +
  "            }\n" +
  "            if ((asm_src[start] & 0xFF) == '-') asm_tok_int = -asm_tok_int;\n" +
  "            asm_tok = WTOK_INT;\n" +
  "            return;\n" +
  "        }\n" +
  "\n" +
  "        /* Decimal number */\n" +
  "        while (asm_pos < asm_src_len && (asm_src[asm_pos] & 0xFF) >= '0' && (asm_src[asm_pos] & 0xFF) <= '9') asm_pos++;\n" +
  "        if (asm_pos < asm_src_len && (asm_src[asm_pos] & 0xFF) == '.') {\n" +
  "            is_float = 1;\n" +
  "            asm_pos++;\n" +
  "            while (asm_pos < asm_src_len && (asm_src[asm_pos] & 0xFF) >= '0' && (asm_src[asm_pos] & 0xFF) <= '9') asm_pos++;\n" +
  "        }\n" +
  "        if (asm_pos < asm_src_len && ((asm_src[asm_pos] & 0xFF) == 'e' || (asm_src[asm_pos] & 0xFF) == 'E')) {\n" +
  "            is_float = 1;\n" +
  "            asm_pos++;\n" +
  "            if (asm_pos < asm_src_len && ((asm_src[asm_pos] & 0xFF) == '+' || (asm_src[asm_pos] & 0xFF) == '-')) asm_pos++;\n" +
  "            while (asm_pos < asm_src_len && (asm_src[asm_pos] & 0xFF) >= '0' && (asm_src[asm_pos] & 0xFF) <= '9') asm_pos++;\n" +
  "        }\n" +
  "        len = asm_pos - start;\n" +
  "        if (is_float) {\n" +
  "            asm_tok_str = strdupn(asm_src + start, len);\n" +
  "            asm_tok = WTOK_FLOAT;\n" +
  "        } else {\n" +
  "            asm_tok_int = 0;\n" +
  "            p = start;\n" +
  "            sign = 1;\n" +
  "            if ((asm_src[p] & 0xFF) == '-') { sign = -1; p++; }\n" +
  "            while (p < asm_pos) {\n" +
  "                asm_tok_int = asm_tok_int * 10 + ((asm_src[p] & 0xFF) - '0');\n" +
  "                p++;\n" +
  "            }\n" +
  "            asm_tok_int = asm_tok_int * sign;\n" +
  "            asm_tok = WTOK_INT;\n" +
  "        }\n" +
  "        return;\n" +
  "    }\n" +
  "    }\n" +
  "\n" +
  "    /* Keyword */\n" +
  "    start = asm_pos;\n" +
  "    while (asm_pos < asm_src_len) {\n" +
  "        c = asm_src[asm_pos] & 0xFF;\n" +
  "        if (c == ' ' || c == '\\t' || c == '\\n' || c == '\\r' ||\n" +
  "            c == '(' || c == ')') break;\n" +
  "        asm_pos++;\n" +
  "    }\n" +
  "    len = asm_pos - start;\n" +
  "    asm_tok_str = strdupn(asm_src + start, len);\n" +
  "    asm_tok = WTOK_KW;\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Module State\n" +
  " * ================================================================ */\n" +
  "\n" +
  "struct AsmType {\n" +
  "    int nparams;\n" +
  "    int *param_types;\n" +
  "    int nresults;\n" +
  "    int result_type;\n" +
  "};\n" +
  "\n" +
  "struct AsmFunc {\n" +
  "    char *name;\n" +
  "    int type_idx;\n" +
  "    int is_import;\n" +
  "};\n" +
  "\n" +
  "struct AsmImport {\n" +
  "    char *module_name;\n" +
  "    char *field_name;\n" +
  "    int func_idx;\n" +
  "};\n" +
  "\n" +
  "struct AsmGlobal {\n" +
  "    char *name;\n" +
  "    int val_type;\n" +
  "    int is_mutable;\n" +
  "    struct ByteVec *init_expr;\n" +
  "};\n" +
  "\n" +
  "struct AsmData {\n" +
  "    int offset;\n" +
  "    struct ByteVec *bytes;\n" +
  "};\n" +
  "\n" +
  "struct AsmType **asm_types;\n" +
  "int asm_ntypes;\n" +
  "\n" +
  "char **asm_type_names;\n" +
  "int *asm_type_indices;\n" +
  "int asm_ntype_names;\n" +
  "\n" +
  "struct AsmFunc **asm_funcs;\n" +
  "int asm_nfuncs;\n" +
  "int asm_nimports;\n" +
  "\n" +
  "struct AsmImport **asm_imports;\n" +
  "\n" +
  "struct AsmGlobal **asm_globals;\n" +
  "int asm_nglobals;\n" +
  "\n" +
  "struct AsmData **asm_data_segs;\n" +
  "int asm_ndata;\n" +
  "\n" +
  "int asm_memory_pages;\n" +
  "char *asm_mem_export_name;\n" +
  "\n" +
  "int asm_has_table;\n" +
  "int asm_table_size;\n" +
  "int *asm_elem_indices;\n" +
  "int asm_nelem;\n" +
  "\n" +
  "/* Export tracking */\n" +
  "char *asm_func_export_name;\n" +
  "int asm_func_export_idx;\n" +
  "\n" +
  "/* Per-function local tracking */\n" +
  "char **asm_local_names;\n" +
  "int *asm_local_types;\n" +
  "int asm_nlocals;\n" +
  "\n" +
  "/* Label stack for block/loop/if */\n" +
  "char **asm_label_stack;\n" +
  "int asm_label_sp;\n" +
  "\n" +
  "/* Function bodies for deferred encoding */\n" +
  "struct ByteVec **asm_func_bodies;\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Name Resolution\n" +
  " * ================================================================ */\n" +
  "\n" +
  "int asm_find_func(char *name) {\n" +
  "    int i;\n" +
  "    for (i = 0; i < asm_nfuncs; i++) {\n" +
  "        if (strcmp(asm_funcs[i]->name, name) == 0) return i;\n" +
  "    }\n" +
  "    printf(\"assembler error: unknown function $%s\\n\", name);\n" +
  "    exit(1);\n" +
  "    return 0;\n" +
  "}\n" +
  "\n" +
  "int asm_find_global(char *name) {\n" +
  "    int i;\n" +
  "    for (i = 0; i < asm_nglobals; i++) {\n" +
  "        if (strcmp(asm_globals[i]->name, name) == 0) return i;\n" +
  "    }\n" +
  "    printf(\"assembler error: unknown global $%s\\n\", name);\n" +
  "    exit(1);\n" +
  "    return 0;\n" +
  "}\n" +
  "\n" +
  "int asm_find_type_by_name(char *name) {\n" +
  "    int i;\n" +
  "    for (i = 0; i < asm_ntype_names; i++) {\n" +
  "        if (strcmp(asm_type_names[i], name) == 0) return asm_type_indices[i];\n" +
  "    }\n" +
  "    printf(\"assembler error: unknown type $%s\\n\", name);\n" +
  "    exit(1);\n" +
  "    return 0;\n" +
  "}\n" +
  "\n" +
  "int asm_find_local(char *name) {\n" +
  "    int i;\n" +
  "    for (i = 0; i < asm_nlocals; i++) {\n" +
  "        if (strcmp(asm_local_names[i], name) == 0) return i;\n" +
  "    }\n" +
  "    printf(\"assembler error: unknown local $%s\\n\", name);\n" +
  "    exit(1);\n" +
  "    return 0;\n" +
  "}\n" +
  "\n" +
  "int asm_find_label(char *name) {\n" +
  "    int i;\n" +
  "    for (i = asm_label_sp - 1; i >= 0; i--) {\n" +
  "        if (asm_label_stack[i] != (char *)0 && strcmp(asm_label_stack[i], name) == 0) {\n" +
  "            return asm_label_sp - 1 - i;\n" +
  "        }\n" +
  "    }\n" +
  "    printf(\"assembler error: unknown label $%s\\n\", name);\n" +
  "    exit(1);\n" +
  "    return 0;\n" +
  "}\n" +
  "\n" +
  "void asm_push_label(char *name) {\n" +
  "    if (asm_label_sp >= ASM_MAX_LABELS) asm_error(\"label stack overflow\");\n" +
  "    asm_label_stack[asm_label_sp] = name;\n" +
  "    asm_label_sp++;\n" +
  "}\n" +
  "\n" +
  "void asm_pop_label(void) {\n" +
  "    if (asm_label_sp > 0) asm_label_sp--;\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Type Deduplication\n" +
  " * ================================================================ */\n" +
  "\n" +
  "int asm_find_or_add_type(int nparams, int *ptypes, int nresults, int rtype) {\n" +
  "    int i;\n" +
  "    int j;\n" +
  "    int match;\n" +
  "    struct AsmType *t;\n" +
  "    for (i = 0; i < asm_ntypes; i++) {\n" +
  "        if (asm_types[i]->nparams != nparams) continue;\n" +
  "        if (asm_types[i]->nresults != nresults) continue;\n" +
  "        if (nresults > 0 && asm_types[i]->result_type != rtype) continue;\n" +
  "        match = 1;\n" +
  "        for (j = 0; j < nparams; j++) {\n" +
  "            if (asm_types[i]->param_types[j] != ptypes[j]) { match = 0; break; }\n" +
  "        }\n" +
  "        if (match) return i;\n" +
  "    }\n" +
  "    if (asm_ntypes >= ASM_MAX_TYPES) asm_error(\"too many types\");\n" +
  "    t = (struct AsmType *)malloc(sizeof(struct AsmType));\n" +
  "    t->nparams = nparams;\n" +
  "    t->param_types = (int *)malloc(ASM_MAX_PARAMS * sizeof(int));\n" +
  "    for (j = 0; j < nparams && j < ASM_MAX_PARAMS; j++) {\n" +
  "        t->param_types[j] = ptypes[j];\n" +
  "    }\n" +
  "    t->nresults = nresults;\n" +
  "    t->result_type = rtype;\n" +
  "    asm_types[asm_ntypes] = t;\n" +
  "    asm_ntypes++;\n" +
  "    return asm_ntypes - 1;\n" +
  "}\n" +
  "\n" +
  "int asm_parse_valtype(char *s) {\n" +
  "    if (strcmp(s, \"i32\") == 0) return 0x7F;\n" +
  "    if (strcmp(s, \"i64\") == 0) return 0x7E;\n" +
  "    if (strcmp(s, \"f64\") == 0) return 0x7C;\n" +
  "    if (strcmp(s, \"f32\") == 0) return 0x7D;\n" +
  "    printf(\"assembler error: unknown valtype %s\\n\", s);\n" +
  "    exit(1);\n" +
  "    return 0x7F;\n" +
  "}\n" +
  "\n" +
  "/* Parse (param ...) and (result ...) to build a type signature.\n" +
  " * Returns type index. Leaves tokenizer past the closing ) of func sig. */\n" +
  "int asm_parse_func_sig(int *out_nparams) {\n" +
  "    int ptypes[16];\n" +
  "    int nparams;\n" +
  "    int nresults;\n" +
  "    int rtype;\n" +
  "\n" +
  "    nparams = 0;\n" +
  "    nresults = 0;\n" +
  "    rtype = 0;\n" +
  "\n" +
  "    /* Parse param and result declarations until we see something else */\n" +
  "    while (asm_tok == WTOK_LPAREN) {\n" +
  "        asm_save();\n" +
  "        asm_next(); /* keyword after ( */\n" +
  "        if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"param\") == 0) {\n" +
  "            asm_next();\n" +
  "            /* Skip optional $name */\n" +
  "            if (asm_tok == WTOK_NAME) asm_next();\n" +
  "            /* Parse one or more types */\n" +
  "            while (asm_tok == WTOK_KW && (strcmp(asm_tok_str, \"i32\") == 0 ||\n" +
  "                   strcmp(asm_tok_str, \"i64\") == 0 || strcmp(asm_tok_str, \"f64\") == 0 ||\n" +
  "                   strcmp(asm_tok_str, \"f32\") == 0)) {\n" +
  "                if (nparams < ASM_MAX_PARAMS) {\n" +
  "                    ptypes[nparams] = asm_parse_valtype(asm_tok_str);\n" +
  "                    nparams++;\n" +
  "                }\n" +
  "                asm_next();\n" +
  "            }\n" +
  "            /* expect ) */\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "        } else if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"result\") == 0) {\n" +
  "            asm_next();\n" +
  "            if (asm_tok == WTOK_KW) {\n" +
  "                rtype = asm_parse_valtype(asm_tok_str);\n" +
  "                nresults = 1;\n" +
  "                asm_next();\n" +
  "            }\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "        } else {\n" +
  "            asm_restore();\n" +
  "            break;\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    if (out_nparams != (int *)0) *out_nparams = nparams;\n" +
  "    return asm_find_or_add_type(nparams, ptypes, nresults, rtype);\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Float Parsing (IEEE 754)\n" +
  " * ================================================================ */\n" +
  "\n" +
  "double asm_parse_float_text(char *s) {\n" +
  "    double result;\n" +
  "    double frac_mult;\n" +
  "    int sign;\n" +
  "    int exp_val;\n" +
  "    int exp_sign;\n" +
  "    int i;\n" +
  "    result = 0.0;\n" +
  "    sign = 1;\n" +
  "    exp_val = 0;\n" +
  "    exp_sign = 1;\n" +
  "    i = 0;\n" +
  "    if (s[i] == '-') { sign = -1; i = i + 1; }\n" +
  "    else if (s[i] == '+') { i = i + 1; }\n" +
  "    while (s[i] >= '0' && s[i] <= '9') {\n" +
  "        result = result * 10.0 + (double)(s[i] - '0');\n" +
  "        i = i + 1;\n" +
  "    }\n" +
  "    if (s[i] == '.') {\n" +
  "        i = i + 1;\n" +
  "        frac_mult = 0.1;\n" +
  "        while (s[i] >= '0' && s[i] <= '9') {\n" +
  "            result = result + (double)(s[i] - '0') * frac_mult;\n" +
  "            frac_mult = frac_mult * 0.1;\n" +
  "            i = i + 1;\n" +
  "        }\n" +
  "    }\n" +
  "    if (s[i] == 'e' || s[i] == 'E') {\n" +
  "        i = i + 1;\n" +
  "        if (s[i] == '-') { exp_sign = -1; i = i + 1; }\n" +
  "        else if (s[i] == '+') { i = i + 1; }\n" +
  "        while (s[i] >= '0' && s[i] <= '9') {\n" +
  "            exp_val = exp_val * 10 + (s[i] - '0');\n" +
  "            i = i + 1;\n" +
  "        }\n" +
  "    }\n" +
  "    if (exp_sign > 0) {\n" +
  "        while (exp_val > 0) { result = result * 10.0; exp_val = exp_val - 1; }\n" +
  "    } else {\n" +
  "        while (exp_val > 0) { result = result * 0.1; exp_val = exp_val - 1; }\n" +
  "    }\n" +
  "    if (sign < 0) result = result * -1.0;\n" +
  "    return result;\n" +
  "}\n" +
  "\n" +
  "void asm_emit_f64(struct ByteVec *code, char *s) {\n" +
  "    double *p;\n" +
  "    char *b;\n" +
  "    int i;\n" +
  "    p = (double *)malloc(8);\n" +
  "    *p = asm_parse_float_text(s);\n" +
  "    b = (char *)p;\n" +
  "    for (i = 0; i < 8; i++) {\n" +
  "        bv_push(code, b[i] & 0xFF);\n" +
  "    }\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * String Decoding (WAT escape sequences)\n" +
  " * ================================================================ */\n" +
  "\n" +
  "int asm_hex_digit(int c) {\n" +
  "    if (c >= '0' && c <= '9') return c - '0';\n" +
  "    if (c >= 'a' && c <= 'f') return 10 + c - 'a';\n" +
  "    if (c >= 'A' && c <= 'F') return 10 + c - 'A';\n" +
  "    return 0;\n" +
  "}\n" +
  "\n" +
  "void asm_decode_string(char *s, int slen, struct ByteVec *dst) {\n" +
  "    int i;\n" +
  "    int c;\n" +
  "    i = 0;\n" +
  "    while (i < slen) {\n" +
  "        c = s[i] & 0xFF;\n" +
  "        if (c == '\\\\' && i + 2 < slen) {\n" +
  "            int c1;\n" +
  "            int c2;\n" +
  "            c1 = s[i + 1] & 0xFF;\n" +
  "            c2 = s[i + 2] & 0xFF;\n" +
  "            if (c1 == '\\\\') {\n" +
  "                bv_push(dst, '\\\\');\n" +
  "                i = i + 2;\n" +
  "            } else if (c1 == '\"') {\n" +
  "                bv_push(dst, '\"');\n" +
  "                i = i + 2;\n" +
  "            } else if (c1 == 'n') {\n" +
  "                bv_push(dst, 10);\n" +
  "                i = i + 2;\n" +
  "            } else if (c1 == 't') {\n" +
  "                bv_push(dst, 9);\n" +
  "                i = i + 2;\n" +
  "            } else if (c1 == 'r') {\n" +
  "                bv_push(dst, 13);\n" +
  "                i = i + 2;\n" +
  "            } else {\n" +
  "                /* hex escape \\HH */\n" +
  "                bv_push(dst, asm_hex_digit(c1) * 16 + asm_hex_digit(c2));\n" +
  "                i = i + 3;\n" +
  "            }\n" +
  "        } else {\n" +
  "            bv_push(dst, c);\n" +
  "            i = i + 1;\n" +
  "        }\n" +
  "    }\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * First Pass — Collect Function Names\n" +
  " * ================================================================ */\n" +
  "\n" +
  "void asm_first_pass(void) {\n" +
  "    int depth;\n" +
  "    depth = 0;\n" +
  "\n" +
  "    while (1) {\n" +
  "        asm_next();\n" +
  "        if (asm_tok == WTOK_EOF) break;\n" +
  "        if (asm_tok == WTOK_LPAREN) {\n" +
  "            depth++;\n" +
  "            continue;\n" +
  "        }\n" +
  "        if (asm_tok == WTOK_RPAREN) {\n" +
  "            depth--;\n" +
  "            continue;\n" +
  "        }\n" +
  "        if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"func\") == 0) {\n" +
  "            asm_next();\n" +
  "            if (asm_tok == WTOK_NAME) {\n" +
  "                int is_imp;\n" +
  "                is_imp = (depth >= 3) ? 1 : 0;\n" +
  "                if (asm_nfuncs >= ASM_MAX_FUNCS) asm_error(\"too many functions\");\n" +
  "                asm_funcs[asm_nfuncs] = (struct AsmFunc *)malloc(sizeof(struct AsmFunc));\n" +
  "                asm_funcs[asm_nfuncs]->name = asm_tok_str;\n" +
  "                asm_funcs[asm_nfuncs]->type_idx = -1;\n" +
  "                asm_funcs[asm_nfuncs]->is_import = is_imp;\n" +
  "                asm_nfuncs++;\n" +
  "                if (is_imp) asm_nimports++;\n" +
  "            }\n" +
  "        }\n" +
  "    }\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Instruction Encoding\n" +
  " * ================================================================ */\n" +
  "\n" +
  "int asm_mem_align(char *instr) {\n" +
  "    if (strcmp(instr, \"i32.load\") == 0) return 2;\n" +
  "    if (strcmp(instr, \"i32.store\") == 0) return 2;\n" +
  "    if (strcmp(instr, \"i32.load8_u\") == 0) return 0;\n" +
  "    if (strcmp(instr, \"i32.store8\") == 0) return 0;\n" +
  "    if (strcmp(instr, \"i32.load16_s\") == 0) return 1;\n" +
  "    if (strcmp(instr, \"i32.store16\") == 0) return 1;\n" +
  "    if (strcmp(instr, \"f64.load\") == 0) return 3;\n" +
  "    if (strcmp(instr, \"f64.store\") == 0) return 3;\n" +
  "    return 0;\n" +
  "}\n" +
  "\n" +
  "/* Parse offset=N from a keyword token like \"offset=4\" */\n" +
  "int asm_parse_offset_val(char *s) {\n" +
  "    int i;\n" +
  "    int val;\n" +
  "    /* skip past \"offset=\" */\n" +
  "    i = 7;\n" +
  "    val = 0;\n" +
  "    while (s[i] >= '0' && s[i] <= '9') {\n" +
  "        val = val * 10 + (s[i] - '0');\n" +
  "        i++;\n" +
  "    }\n" +
  "    return val;\n" +
  "}\n" +
  "\n" +
  "/* Check if current token is offset=N, consume it and set asm_mem_offset */\n" +
  "void asm_check_offset(void) {\n" +
  "    if (asm_tok == WTOK_KW && asm_tok_str[0] == 'o' &&\n" +
  "        strncmp(asm_tok_str, \"offset=\", 7) == 0) {\n" +
  "        asm_mem_offset = asm_parse_offset_val(asm_tok_str);\n" +
  "        asm_next();\n" +
  "    }\n" +
  "}\n" +
  "\n" +
  "void asm_encode_mem_instr(struct ByteVec *code, int opcode, char *instr) {\n" +
  "    bv_push(code, opcode);\n" +
  "    bv_u32(code, asm_mem_align(instr));\n" +
  "    bv_u32(code, asm_mem_offset);\n" +
  "    asm_mem_offset = 0;\n" +
  "}\n" +
  "\n" +
  "void asm_encode_instr(char *kw, struct ByteVec *code) {\n" +
  "    /* Constants */\n" +
  "    if (strcmp(kw, \"i32.const\") == 0) {\n" +
  "        bv_push(code, 0x41);\n" +
  "        if (asm_tok == WTOK_INT) { bv_i32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected integer after i32.const\");\n" +
  "        return;\n" +
  "    }\n" +
  "    if (strcmp(kw, \"i64.const\") == 0) {\n" +
  "        bv_push(code, 0x42);\n" +
  "        if (asm_tok == WTOK_INT) { bv_i32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected integer after i64.const\");\n" +
  "        return;\n" +
  "    }\n" +
  "    if (strcmp(kw, \"f64.const\") == 0) {\n" +
  "        bv_push(code, 0x44);\n" +
  "        if (asm_tok == WTOK_FLOAT) { asm_emit_f64(code, asm_tok_str); asm_next(); }\n" +
  "        else if (asm_tok == WTOK_INT) {\n" +
  "            /* Integer literal used as float, e.g. f64.const 0 */\n" +
  "            char buf[20];\n" +
  "            int v;\n" +
  "            int bi;\n" +
  "            v = asm_tok_int;\n" +
  "            bi = 0;\n" +
  "            if (v < 0) { buf[bi] = '-'; bi++; v = -v; }\n" +
  "            if (v == 0) { buf[bi] = '0'; bi++; }\n" +
  "            else {\n" +
  "                char tmp[12];\n" +
  "                int ti;\n" +
  "                ti = 0;\n" +
  "                while (v > 0) { tmp[ti] = '0' + (v % 10); ti++; v = v / 10; }\n" +
  "                while (ti > 0) { ti--; buf[bi] = tmp[ti]; bi++; }\n" +
  "            }\n" +
  "            buf[bi] = '.';\n" +
  "            bi++;\n" +
  "            buf[bi] = '0';\n" +
  "            bi++;\n" +
  "            buf[bi] = 0;\n" +
  "            asm_emit_f64(code, buf);\n" +
  "            asm_next();\n" +
  "        }\n" +
  "        else asm_error(\"expected number after f64.const\");\n" +
  "        return;\n" +
  "    }\n" +
  "\n" +
  "    /* Local/global variable access */\n" +
  "    if (strcmp(kw, \"local.get\") == 0) {\n" +
  "        bv_push(code, 0x20);\n" +
  "        if (asm_tok == WTOK_NAME) { bv_u32(code, asm_find_local(asm_tok_str)); asm_next(); }\n" +
  "        else if (asm_tok == WTOK_INT) { bv_u32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected local name/index\");\n" +
  "        return;\n" +
  "    }\n" +
  "    if (strcmp(kw, \"local.set\") == 0) {\n" +
  "        bv_push(code, 0x21);\n" +
  "        if (asm_tok == WTOK_NAME) { bv_u32(code, asm_find_local(asm_tok_str)); asm_next(); }\n" +
  "        else if (asm_tok == WTOK_INT) { bv_u32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected local name/index\");\n" +
  "        return;\n" +
  "    }\n" +
  "    if (strcmp(kw, \"local.tee\") == 0) {\n" +
  "        bv_push(code, 0x22);\n" +
  "        if (asm_tok == WTOK_NAME) { bv_u32(code, asm_find_local(asm_tok_str)); asm_next(); }\n" +
  "        else if (asm_tok == WTOK_INT) { bv_u32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected local name/index\");\n" +
  "        return;\n" +
  "    }\n" +
  "    if (strcmp(kw, \"global.get\") == 0) {\n" +
  "        bv_push(code, 0x23);\n" +
  "        if (asm_tok == WTOK_NAME) { bv_u32(code, asm_find_global(asm_tok_str)); asm_next(); }\n" +
  "        else if (asm_tok == WTOK_INT) { bv_u32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected global name/index\");\n" +
  "        return;\n" +
  "    }\n" +
  "    if (strcmp(kw, \"global.set\") == 0) {\n" +
  "        bv_push(code, 0x24);\n" +
  "        if (asm_tok == WTOK_NAME) { bv_u32(code, asm_find_global(asm_tok_str)); asm_next(); }\n" +
  "        else if (asm_tok == WTOK_INT) { bv_u32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected global name/index\");\n" +
  "        return;\n" +
  "    }\n" +
  "\n" +
  "    /* Call */\n" +
  "    if (strcmp(kw, \"call\") == 0) {\n" +
  "        bv_push(code, 0x10);\n" +
  "        if (asm_tok == WTOK_NAME) { bv_u32(code, asm_find_func(asm_tok_str)); asm_next(); }\n" +
  "        else if (asm_tok == WTOK_INT) { bv_u32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected function name/index\");\n" +
  "        return;\n" +
  "    }\n" +
  "    if (strcmp(kw, \"call_indirect\") == 0) {\n" +
  "        int type_idx;\n" +
  "        /* Expect (type $name) */\n" +
  "        if (asm_tok != WTOK_LPAREN) asm_error(\"expected (type ...) after call_indirect\");\n" +
  "        asm_next(); /* \"type\" keyword */\n" +
  "        asm_next(); /* $name */\n" +
  "        type_idx = asm_tok == WTOK_NAME ? asm_find_type_by_name(asm_tok_str) : asm_tok_int;\n" +
  "        asm_next(); /* ) */\n" +
  "        if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "        bv_push(code, 0x11);\n" +
  "        bv_u32(code, type_idx);\n" +
  "        bv_u32(code, 0); /* table index 0 */\n" +
  "        return;\n" +
  "    }\n" +
  "\n" +
  "    /* Branch */\n" +
  "    if (strcmp(kw, \"br\") == 0) {\n" +
  "        bv_push(code, 0x0C);\n" +
  "        if (asm_tok == WTOK_NAME) { bv_u32(code, asm_find_label(asm_tok_str)); asm_next(); }\n" +
  "        else if (asm_tok == WTOK_INT) { bv_u32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected label after br\");\n" +
  "        return;\n" +
  "    }\n" +
  "    if (strcmp(kw, \"br_if\") == 0) {\n" +
  "        bv_push(code, 0x0D);\n" +
  "        if (asm_tok == WTOK_NAME) { bv_u32(code, asm_find_label(asm_tok_str)); asm_next(); }\n" +
  "        else if (asm_tok == WTOK_INT) { bv_u32(code, asm_tok_int); asm_next(); }\n" +
  "        else asm_error(\"expected label after br_if\");\n" +
  "        return;\n" +
  "    }\n" +
  "\n" +
  "    /* Memory instructions */\n" +
  "    if (strcmp(kw, \"i32.load\") == 0) { asm_encode_mem_instr(code, 0x28, kw); return; }\n" +
  "    if (strcmp(kw, \"f64.load\") == 0) { asm_encode_mem_instr(code, 0x2B, kw); return; }\n" +
  "    if (strcmp(kw, \"i32.load8_u\") == 0) { asm_encode_mem_instr(code, 0x2D, kw); return; }\n" +
  "    if (strcmp(kw, \"i32.load16_s\") == 0) { asm_encode_mem_instr(code, 0x2E, kw); return; }\n" +
  "    if (strcmp(kw, \"i32.store\") == 0) { asm_encode_mem_instr(code, 0x36, kw); return; }\n" +
  "    if (strcmp(kw, \"f64.store\") == 0) { asm_encode_mem_instr(code, 0x39, kw); return; }\n" +
  "    if (strcmp(kw, \"i32.store8\") == 0) { asm_encode_mem_instr(code, 0x3A, kw); return; }\n" +
  "    if (strcmp(kw, \"i32.store16\") == 0) { asm_encode_mem_instr(code, 0x3B, kw); return; }\n" +
  "\n" +
  "    /* Simple opcodes (no immediate) */\n" +
  "    if (strcmp(kw, \"drop\") == 0) { bv_push(code, 0x1A); return; }\n" +
  "    if (strcmp(kw, \"return\") == 0) { bv_push(code, 0x0F); return; }\n" +
  "    if (strcmp(kw, \"i32.eqz\") == 0) { bv_push(code, 0x45); return; }\n" +
  "    if (strcmp(kw, \"i32.eq\") == 0) { bv_push(code, 0x46); return; }\n" +
  "    if (strcmp(kw, \"i32.ne\") == 0) { bv_push(code, 0x47); return; }\n" +
  "    if (strcmp(kw, \"i32.lt_s\") == 0) { bv_push(code, 0x48); return; }\n" +
  "    if (strcmp(kw, \"i32.lt_u\") == 0) { bv_push(code, 0x49); return; }\n" +
  "    if (strcmp(kw, \"i32.gt_s\") == 0) { bv_push(code, 0x4A); return; }\n" +
  "    if (strcmp(kw, \"i32.gt_u\") == 0) { bv_push(code, 0x4B); return; }\n" +
  "    if (strcmp(kw, \"i32.le_s\") == 0) { bv_push(code, 0x4C); return; }\n" +
  "    if (strcmp(kw, \"i32.le_u\") == 0) { bv_push(code, 0x4D); return; }\n" +
  "    if (strcmp(kw, \"i32.ge_s\") == 0) { bv_push(code, 0x4E); return; }\n" +
  "    if (strcmp(kw, \"i32.ge_u\") == 0) { bv_push(code, 0x4F); return; }\n" +
  "    if (strcmp(kw, \"i32.add\") == 0) { bv_push(code, 0x6A); return; }\n" +
  "    if (strcmp(kw, \"i32.sub\") == 0) { bv_push(code, 0x6B); return; }\n" +
  "    if (strcmp(kw, \"i32.mul\") == 0) { bv_push(code, 0x6C); return; }\n" +
  "    if (strcmp(kw, \"i32.div_s\") == 0) { bv_push(code, 0x6D); return; }\n" +
  "    if (strcmp(kw, \"i32.div_u\") == 0) { bv_push(code, 0x6E); return; }\n" +
  "    if (strcmp(kw, \"i32.rem_s\") == 0) { bv_push(code, 0x6F); return; }\n" +
  "    if (strcmp(kw, \"i32.rem_u\") == 0) { bv_push(code, 0x70); return; }\n" +
  "    if (strcmp(kw, \"i32.and\") == 0) { bv_push(code, 0x71); return; }\n" +
  "    if (strcmp(kw, \"i32.or\") == 0) { bv_push(code, 0x72); return; }\n" +
  "    if (strcmp(kw, \"i32.xor\") == 0) { bv_push(code, 0x73); return; }\n" +
  "    if (strcmp(kw, \"i32.shl\") == 0) { bv_push(code, 0x74); return; }\n" +
  "    if (strcmp(kw, \"i32.shr_s\") == 0) { bv_push(code, 0x75); return; }\n" +
  "    if (strcmp(kw, \"i32.shr_u\") == 0) { bv_push(code, 0x76); return; }\n" +
  "    if (strcmp(kw, \"f64.eq\") == 0) { bv_push(code, 0x61); return; }\n" +
  "    if (strcmp(kw, \"f64.ne\") == 0) { bv_push(code, 0x62); return; }\n" +
  "    if (strcmp(kw, \"f64.lt\") == 0) { bv_push(code, 0x63); return; }\n" +
  "    if (strcmp(kw, \"f64.gt\") == 0) { bv_push(code, 0x64); return; }\n" +
  "    if (strcmp(kw, \"f64.le\") == 0) { bv_push(code, 0x65); return; }\n" +
  "    if (strcmp(kw, \"f64.ge\") == 0) { bv_push(code, 0x66); return; }\n" +
  "    if (strcmp(kw, \"f64.neg\") == 0) { bv_push(code, 0x9A); return; }\n" +
  "    if (strcmp(kw, \"f64.add\") == 0) { bv_push(code, 0xA0); return; }\n" +
  "    if (strcmp(kw, \"f64.sub\") == 0) { bv_push(code, 0xA1); return; }\n" +
  "    if (strcmp(kw, \"f64.mul\") == 0) { bv_push(code, 0xA2); return; }\n" +
  "    if (strcmp(kw, \"f64.div\") == 0) { bv_push(code, 0xA3); return; }\n" +
  "    if (strcmp(kw, \"i32.trunc_f64_s\") == 0) { bv_push(code, 0xAA); return; }\n" +
  "    if (strcmp(kw, \"f64.convert_i32_s\") == 0) { bv_push(code, 0xB7); return; }\n" +
  "\n" +
  "    printf(\"assembler error: unknown instruction '%s'\\n\", kw);\n" +
  "    exit(1);\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Expression Parser (recursive, handles folded + flat WAT)\n" +
  " * ================================================================ */\n" +
  "\n" +
  "void asm_parse_expr(struct ByteVec *code);\n" +
  "\n" +
  "/* Parse a block type: (result valtype) or nothing (void 0x40) */\n" +
  "int asm_parse_blocktype(void) {\n" +
  "    if (asm_tok == WTOK_LPAREN) {\n" +
  "        asm_save();\n" +
  "        asm_next();\n" +
  "        if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"result\") == 0) {\n" +
  "            int bt;\n" +
  "            asm_next();\n" +
  "            bt = asm_parse_valtype(asm_tok_str);\n" +
  "            asm_next(); /* skip type */\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "            return bt;\n" +
  "        }\n" +
  "        asm_restore();\n" +
  "    }\n" +
  "    return 0x40; /* void block type */\n" +
  "}\n" +
  "\n" +
  "/* Check if current ( starts a then/else clause */\n" +
  "int asm_peek_is_then_or_else(void) {\n" +
  "    int result;\n" +
  "    if (asm_tok != WTOK_LPAREN) return 0;\n" +
  "    asm_save();\n" +
  "    asm_next();\n" +
  "    result = (asm_tok == WTOK_KW &&\n" +
  "              (strcmp(asm_tok_str, \"then\") == 0 || strcmp(asm_tok_str, \"else\") == 0));\n" +
  "    asm_restore();\n" +
  "    return result;\n" +
  "}\n" +
  "\n" +
  "void asm_parse_folded_block(struct ByteVec *code) {\n" +
  "    /* Current token is the keyword: block/loop */\n" +
  "    char *kw;\n" +
  "    int opcode;\n" +
  "    int bt;\n" +
  "    char *label;\n" +
  "    kw = asm_tok_str;\n" +
  "    opcode = (strcmp(kw, \"block\") == 0) ? 0x02 : 0x03;\n" +
  "    asm_next();\n" +
  "\n" +
  "    /* Optional label */\n" +
  "    label = (char *)0;\n" +
  "    if (asm_tok == WTOK_NAME) {\n" +
  "        label = asm_tok_str;\n" +
  "        asm_next();\n" +
  "    }\n" +
  "\n" +
  "    bt = asm_parse_blocktype();\n" +
  "    bv_push(code, opcode);\n" +
  "    bv_push(code, bt);\n" +
  "    asm_push_label(label);\n" +
  "\n" +
  "    /* Parse body until ) */\n" +
  "    while (asm_tok != WTOK_RPAREN && asm_tok != WTOK_EOF) {\n" +
  "        asm_parse_expr(code);\n" +
  "    }\n" +
  "\n" +
  "    bv_push(code, 0x0B); /* end */\n" +
  "    asm_pop_label();\n" +
  "    if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "}\n" +
  "\n" +
  "void asm_parse_folded_if(struct ByteVec *code) {\n" +
  "    /* Current token is \"if\" keyword */\n" +
  "    int bt;\n" +
  "    char *label;\n" +
  "    asm_next(); /* past \"if\" */\n" +
  "\n" +
  "    /* Optional label for if (rare but possible) */\n" +
  "    label = (char *)0;\n" +
  "    if (asm_tok == WTOK_NAME) {\n" +
  "        label = asm_tok_str;\n" +
  "        asm_next();\n" +
  "    }\n" +
  "\n" +
  "    /* Parse block type */\n" +
  "    bt = asm_parse_blocktype();\n" +
  "\n" +
  "    /* Parse condition expressions (everything before (then ...)) */\n" +
  "    while (asm_tok != WTOK_EOF && asm_tok != WTOK_RPAREN) {\n" +
  "        if (asm_peek_is_then_or_else()) break;\n" +
  "        asm_parse_expr(code);\n" +
  "    }\n" +
  "\n" +
  "    /* Emit if instruction */\n" +
  "    bv_push(code, 0x04);\n" +
  "    bv_push(code, bt);\n" +
  "    asm_push_label(label);\n" +
  "\n" +
  "    /* Parse (then ...) */\n" +
  "    if (asm_tok == WTOK_LPAREN) {\n" +
  "        asm_next(); /* ( */\n" +
  "        if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"then\") == 0) {\n" +
  "            asm_next(); /* skip \"then\" */\n" +
  "            while (asm_tok != WTOK_RPAREN && asm_tok != WTOK_EOF) {\n" +
  "                asm_parse_expr(code);\n" +
  "            }\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next(); /* close then */\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    /* Parse optional (else ...) */\n" +
  "    if (asm_tok == WTOK_LPAREN) {\n" +
  "        asm_save();\n" +
  "        asm_next();\n" +
  "        if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"else\") == 0) {\n" +
  "            asm_next(); /* skip \"else\" */\n" +
  "            bv_push(code, 0x05); /* else opcode */\n" +
  "            while (asm_tok != WTOK_RPAREN && asm_tok != WTOK_EOF) {\n" +
  "                asm_parse_expr(code);\n" +
  "            }\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next(); /* close else */\n" +
  "        } else {\n" +
  "            asm_restore();\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    bv_push(code, 0x0B); /* end */\n" +
  "    asm_pop_label();\n" +
  "    if (asm_tok == WTOK_RPAREN) asm_next(); /* close if */\n" +
  "}\n" +
  "\n" +
  "void asm_parse_expr(struct ByteVec *code) {\n" +
  "    char *kw;\n" +
  "\n" +
  "    if (asm_tok == WTOK_LPAREN) {\n" +
  "        /* Folded expression */\n" +
  "        asm_next(); /* keyword */\n" +
  "        if (asm_tok != WTOK_KW) {\n" +
  "            /* Unexpected — skip to matching ) */\n" +
  "            int depth;\n" +
  "            depth = 1;\n" +
  "            while (depth > 0 && asm_tok != WTOK_EOF) {\n" +
  "                asm_next();\n" +
  "                if (asm_tok == WTOK_LPAREN) depth++;\n" +
  "                if (asm_tok == WTOK_RPAREN) depth--;\n" +
  "            }\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "            return;\n" +
  "        }\n" +
  "\n" +
  "        kw = asm_tok_str;\n" +
  "\n" +
  "        /* Control flow: block, loop, if */\n" +
  "        if (strcmp(kw, \"block\") == 0 || strcmp(kw, \"loop\") == 0) {\n" +
  "            asm_parse_folded_block(code);\n" +
  "            return;\n" +
  "        }\n" +
  "        if (strcmp(kw, \"if\") == 0) {\n" +
  "            asm_parse_folded_if(code);\n" +
  "            return;\n" +
  "        }\n" +
  "\n" +
  "        /* Regular folded instruction: (instr [immediate] [sub-exprs] ) */\n" +
  "        asm_next(); /* move past keyword to first arg */\n" +
  "\n" +
  "        /* Check for offset=N on memory instructions */\n" +
  "        asm_check_offset();\n" +
  "\n" +
  "        /* Consume any immediate (before sub-expressions) */\n" +
  "        /* For instructions like (call $fn ...) or (local.get $x), the immediate\n" +
  "         * comes right after the keyword. For (i32.const 42), same thing.\n" +
  "         * For call_indirect, the (type $t) is an immediate group. */\n" +
  "        if (strcmp(kw, \"call_indirect\") == 0) {\n" +
  "            /* Handle (call_indirect (type $name) sub-exprs...) */\n" +
  "            /* First parse sub-expressions (operands on stack) */\n" +
  "            /* But call_indirect is special: (type $name) is an immediate,\n" +
  "             * and the table index is on the stack before call_indirect */\n" +
  "            /* Process sub-exprs first, then encode */\n" +
  "            /* Actually in folded form, sub-exprs come after the immediate */\n" +
  "            /* Let me handle this properly */\n" +
  "            int type_idx;\n" +
  "            type_idx = -1;\n" +
  "            if (asm_tok == WTOK_LPAREN) {\n" +
  "                asm_save();\n" +
  "                asm_next();\n" +
  "                if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"type\") == 0) {\n" +
  "                    asm_next(); /* $name */\n" +
  "                    if (asm_tok == WTOK_NAME) type_idx = asm_find_type_by_name(asm_tok_str);\n" +
  "                    else type_idx = asm_tok_int;\n" +
  "                    asm_next(); /* ) */\n" +
  "                    if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                } else {\n" +
  "                    asm_restore();\n" +
  "                }\n" +
  "            }\n" +
  "            /* Parse operand sub-expressions */\n" +
  "            while (asm_tok == WTOK_LPAREN) {\n" +
  "                asm_parse_expr(code);\n" +
  "            }\n" +
  "            bv_push(code, 0x11);\n" +
  "            bv_u32(code, type_idx);\n" +
  "            bv_u32(code, 0);\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "            return;\n" +
  "        }\n" +
  "\n" +
  "        /* For instructions with named/int immediates, collect them */\n" +
  "        /* But also need to handle sub-expressions that come after */\n" +
  "        {\n" +
  "            char *saved_kw;\n" +
  "            int has_name_imm;\n" +
  "            char *name_imm;\n" +
  "            int has_int_imm;\n" +
  "            int int_imm;\n" +
  "            int has_float_imm;\n" +
  "            char *float_imm;\n" +
  "            int saved_mem_offset;\n" +
  "\n" +
  "            saved_kw = kw;\n" +
  "            has_name_imm = 0;\n" +
  "            name_imm = (char *)0;\n" +
  "            has_int_imm = 0;\n" +
  "            int_imm = 0;\n" +
  "            has_float_imm = 0;\n" +
  "            float_imm = (char *)0;\n" +
  "            saved_mem_offset = asm_mem_offset;\n" +
  "\n" +
  "            /* Check if there's an immediate before sub-expressions */\n" +
  "            if (asm_tok == WTOK_NAME) {\n" +
  "                has_name_imm = 1;\n" +
  "                name_imm = asm_tok_str;\n" +
  "                asm_next();\n" +
  "            } else if (asm_tok == WTOK_INT && strcmp(saved_kw, \"i32.const\") != 0 &&\n" +
  "                       strcmp(saved_kw, \"i64.const\") != 0 && strcmp(saved_kw, \"f64.const\") != 0) {\n" +
  "                /* Some instructions take int immediates */\n" +
  "            } else if (asm_tok == WTOK_INT || asm_tok == WTOK_FLOAT) {\n" +
  "                /* Constant instructions */\n" +
  "                if (asm_tok == WTOK_INT) { has_int_imm = 1; int_imm = asm_tok_int; }\n" +
  "                else { has_float_imm = 1; float_imm = asm_tok_str; }\n" +
  "                asm_next();\n" +
  "            }\n" +
  "\n" +
  "            /* Parse sub-expressions (operands) */\n" +
  "            while (asm_tok == WTOK_LPAREN) {\n" +
  "                asm_parse_expr(code);\n" +
  "            }\n" +
  "\n" +
  "            /* Restore mem offset (sub-expressions may have overwritten it) */\n" +
  "            asm_mem_offset = saved_mem_offset;\n" +
  "\n" +
  "            /* Encode instruction with saved immediates.\n" +
  "             * asm_encode_instr reads from asm_tok and may call asm_next(),\n" +
  "             * so save/restore the full tokenizer state around the call. */\n" +
  "            {\n" +
  "                int enc_save_pos;\n" +
  "                int enc_save_tok;\n" +
  "                char *enc_save_str;\n" +
  "                int enc_save_int;\n" +
  "\n" +
  "                enc_save_pos = asm_pos;\n" +
  "                enc_save_tok = asm_tok;\n" +
  "                enc_save_str = asm_tok_str;\n" +
  "                enc_save_int = asm_tok_int;\n" +
  "\n" +
  "                if (has_name_imm) {\n" +
  "                    asm_tok = WTOK_NAME;\n" +
  "                    asm_tok_str = name_imm;\n" +
  "                } else if (has_int_imm) {\n" +
  "                    asm_tok = WTOK_INT;\n" +
  "                    asm_tok_int = int_imm;\n" +
  "                } else if (has_float_imm) {\n" +
  "                    asm_tok = WTOK_FLOAT;\n" +
  "                    asm_tok_str = float_imm;\n" +
  "                }\n" +
  "\n" +
  "                asm_encode_instr(saved_kw, code);\n" +
  "\n" +
  "                asm_pos = enc_save_pos;\n" +
  "                asm_tok = enc_save_tok;\n" +
  "                asm_tok_str = enc_save_str;\n" +
  "                asm_tok_int = enc_save_int;\n" +
  "            }\n" +
  "\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "        }\n" +
  "        return;\n" +
  "    }\n" +
  "\n" +
  "    /* Flat instruction */\n" +
  "    if (asm_tok == WTOK_KW) {\n" +
  "        kw = asm_tok_str;\n" +
  "\n" +
  "        /* Flat control flow */\n" +
  "        if (strcmp(kw, \"block\") == 0 || strcmp(kw, \"loop\") == 0) {\n" +
  "            int opcode;\n" +
  "            int bt;\n" +
  "            char *label;\n" +
  "            opcode = (strcmp(kw, \"block\") == 0) ? 0x02 : 0x03;\n" +
  "            asm_next();\n" +
  "            label = (char *)0;\n" +
  "            if (asm_tok == WTOK_NAME) { label = asm_tok_str; asm_next(); }\n" +
  "            bt = asm_parse_blocktype();\n" +
  "            bv_push(code, opcode);\n" +
  "            bv_push(code, bt);\n" +
  "            asm_push_label(label);\n" +
  "            return;\n" +
  "        }\n" +
  "        if (strcmp(kw, \"if\") == 0) {\n" +
  "            int bt;\n" +
  "            asm_next();\n" +
  "            bt = asm_parse_blocktype();\n" +
  "            bv_push(code, 0x04);\n" +
  "            bv_push(code, bt);\n" +
  "            asm_push_label((char *)0);\n" +
  "            return;\n" +
  "        }\n" +
  "        if (strcmp(kw, \"else\") == 0) {\n" +
  "            bv_push(code, 0x05);\n" +
  "            asm_next();\n" +
  "            return;\n" +
  "        }\n" +
  "        if (strcmp(kw, \"end\") == 0) {\n" +
  "            bv_push(code, 0x0B);\n" +
  "            asm_pop_label();\n" +
  "            asm_next();\n" +
  "            return;\n" +
  "        }\n" +
  "        if (strcmp(kw, \"then\") == 0) {\n" +
  "            /* \"then\" in flat form is a no-op */\n" +
  "            asm_next();\n" +
  "            return;\n" +
  "        }\n" +
  "\n" +
  "        /* Regular flat instruction */\n" +
  "        asm_next(); /* advance past keyword to potential immediate */\n" +
  "        asm_check_offset();\n" +
  "        asm_encode_instr(kw, code);\n" +
  "        return;\n" +
  "    }\n" +
  "\n" +
  "    /* Skip anything else (shouldn't happen) */\n" +
  "    asm_next();\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Function Body Parser\n" +
  " * ================================================================ */\n" +
  "\n" +
  "void asm_parse_func_body(int func_idx, struct ByteVec *body) {\n" +
  "    struct ByteVec *code;\n" +
  "    int nparams;\n" +
  "    int nlocals_only;\n" +
  "    int i;\n" +
  "    int group_type;\n" +
  "    int group_count;\n" +
  "    int ngroups;\n" +
  "    struct ByteVec *locals_buf;\n" +
  "    (void)func_idx;\n" +
  "\n" +
  "    code = bv_new(4096);\n" +
  "    locals_buf = bv_new(256);\n" +
  "\n" +
  "    /* Parse params and locals to build local name table */\n" +
  "    asm_nlocals = 0;\n" +
  "    nparams = 0;\n" +
  "\n" +
  "    /* Parse (param ...) declarations */\n" +
  "    while (asm_tok == WTOK_LPAREN) {\n" +
  "        asm_save();\n" +
  "        asm_next();\n" +
  "        if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"param\") == 0) {\n" +
  "            asm_next();\n" +
  "            if (asm_tok == WTOK_NAME) {\n" +
  "                /* Named param: (param $name type) */\n" +
  "                char *pname;\n" +
  "                int ptype;\n" +
  "                pname = asm_tok_str;\n" +
  "                asm_next();\n" +
  "                ptype = asm_parse_valtype(asm_tok_str);\n" +
  "                asm_next();\n" +
  "                if (asm_nlocals < ASM_MAX_LOCALS) {\n" +
  "                    asm_local_names[asm_nlocals] = pname;\n" +
  "                    asm_local_types[asm_nlocals] = ptype;\n" +
  "                    asm_nlocals++;\n" +
  "                    nparams++;\n" +
  "                }\n" +
  "            } else {\n" +
  "                /* Unnamed params: (param i32 i32 ...) */\n" +
  "                while (asm_tok == WTOK_KW && (strcmp(asm_tok_str, \"i32\") == 0 ||\n" +
  "                       strcmp(asm_tok_str, \"i64\") == 0 || strcmp(asm_tok_str, \"f64\") == 0)) {\n" +
  "                    if (asm_nlocals < ASM_MAX_LOCALS) {\n" +
  "                        asm_local_names[asm_nlocals] = (char *)0;\n" +
  "                        asm_local_types[asm_nlocals] = asm_parse_valtype(asm_tok_str);\n" +
  "                        asm_nlocals++;\n" +
  "                        nparams++;\n" +
  "                    }\n" +
  "                    asm_next();\n" +
  "                }\n" +
  "            }\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "        } else {\n" +
  "            asm_restore();\n" +
  "            break;\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    /* Parse (result ...) — skip it, already handled in type */\n" +
  "    if (asm_tok == WTOK_LPAREN) {\n" +
  "        asm_save();\n" +
  "        asm_next();\n" +
  "        if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"result\") == 0) {\n" +
  "            asm_next(); /* valtype */\n" +
  "            asm_next(); /* ) */\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "        } else {\n" +
  "            asm_restore();\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    /* Parse (local ...) declarations */\n" +
  "    while (asm_tok == WTOK_LPAREN) {\n" +
  "        asm_save();\n" +
  "        asm_next();\n" +
  "        if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"local\") == 0) {\n" +
  "            asm_next();\n" +
  "            if (asm_tok == WTOK_NAME) {\n" +
  "                /* Named local: (local $name type) */\n" +
  "                char *lname;\n" +
  "                int ltype;\n" +
  "                lname = asm_tok_str;\n" +
  "                asm_next();\n" +
  "                ltype = asm_parse_valtype(asm_tok_str);\n" +
  "                asm_next();\n" +
  "                if (asm_nlocals < ASM_MAX_LOCALS) {\n" +
  "                    asm_local_names[asm_nlocals] = lname;\n" +
  "                    asm_local_types[asm_nlocals] = ltype;\n" +
  "                    asm_nlocals++;\n" +
  "                }\n" +
  "            } else {\n" +
  "                /* Unnamed locals: (local i32 ...) */\n" +
  "                while (asm_tok == WTOK_KW) {\n" +
  "                    if (asm_nlocals < ASM_MAX_LOCALS) {\n" +
  "                        asm_local_names[asm_nlocals] = (char *)0;\n" +
  "                        asm_local_types[asm_nlocals] = asm_parse_valtype(asm_tok_str);\n" +
  "                        asm_nlocals++;\n" +
  "                    }\n" +
  "                    asm_next();\n" +
  "                }\n" +
  "            }\n" +
  "            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "        } else {\n" +
  "            asm_restore();\n" +
  "            break;\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    /* Encode local declarations (grouped by consecutive same type) */\n" +
  "    nlocals_only = asm_nlocals - nparams;\n" +
  "    if (nlocals_only > 0) {\n" +
  "        /* Count groups of consecutive same-type locals */\n" +
  "        ngroups = 0;\n" +
  "        i = nparams;\n" +
  "        while (i < asm_nlocals) {\n" +
  "            group_type = asm_local_types[i];\n" +
  "            group_count = 0;\n" +
  "            while (i < asm_nlocals && asm_local_types[i] == group_type) {\n" +
  "                group_count++;\n" +
  "                i++;\n" +
  "            }\n" +
  "            bv_u32(locals_buf, group_count);\n" +
  "            bv_push(locals_buf, group_type);\n" +
  "            ngroups++;\n" +
  "        }\n" +
  "        bv_u32(code, ngroups);\n" +
  "        bv_append(code, locals_buf);\n" +
  "    } else {\n" +
  "        bv_u32(code, 0);\n" +
  "    }\n" +
  "\n" +
  "    /* Reset label stack */\n" +
  "    asm_label_sp = 0;\n" +
  "\n" +
  "    /* Parse instruction body */\n" +
  "    {\n" +
  "        while (asm_tok != WTOK_RPAREN && asm_tok != WTOK_EOF) {\n" +
  "            asm_parse_expr(code);\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    /* end opcode */\n" +
  "    bv_push(code, 0x0B);\n" +
  "\n" +
  "    /* Write to body: size prefix + code */\n" +
  "    bv_u32(body, code->len);\n" +
  "    bv_append(body, code);\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Second Pass — Parse and Encode Module\n" +
  " * ================================================================ */\n" +
  "\n" +
  "void asm_second_pass(void) {\n" +
  "    struct ByteVec *wasm;\n" +
  "    struct ByteVec *sec;\n" +
  "    struct ByteVec *code_sec;\n" +
  "    int nlocal_funcs;\n" +
  "    int i;\n" +
  "    int j;\n" +
  "\n" +
  "    wasm = bv_new(65536);\n" +
  "    sec = bv_new(32768);\n" +
  "    code_sec = bv_new(32768);\n" +
  "\n" +
  "    /* Initialize module state */\n" +
  "    asm_nglobals = 0;\n" +
  "    asm_ndata = 0;\n" +
  "    asm_ntypes = 0;\n" +
  "    asm_ntype_names = 0;\n" +
  "    asm_memory_pages = 256;\n" +
  "    asm_mem_export_name = (char *)0;\n" +
  "    asm_has_table = 0;\n" +
  "    asm_table_size = 0;\n" +
  "    asm_nelem = 0;\n" +
  "    asm_func_export_name = (char *)0;\n" +
  "    asm_func_export_idx = -1;\n" +
  "\n" +
  "    /* Skip past (module */\n" +
  "    asm_next(); /* ( */\n" +
  "    asm_next(); /* module */\n" +
  "    asm_next(); /* first form */\n" +
  "\n" +
  "    /* Process all top-level forms */\n" +
  "    while (asm_tok != WTOK_RPAREN && asm_tok != WTOK_EOF) {\n" +
  "        if (asm_tok == WTOK_LPAREN) {\n" +
  "            asm_next(); /* keyword */\n" +
  "\n" +
  "            if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"import\") == 0) {\n" +
  "                /* (import \"module\" \"field\" (func $name (param ...) (result ...))) */\n" +
  "                char *mod_name;\n" +
  "                char *field_name;\n" +
  "                int imp_idx;\n" +
  "                int type_idx;\n" +
  "                asm_next(); /* module string */\n" +
  "                mod_name = asm_tok_str;\n" +
  "                asm_next(); /* field string */\n" +
  "                field_name = asm_tok_str;\n" +
  "                asm_next(); /* ( */\n" +
  "                asm_next(); /* \"func\" */\n" +
  "                asm_next(); /* $name */\n" +
  "                /* Find the import index from first pass */\n" +
  "                imp_idx = asm_find_func(asm_tok_str);\n" +
  "                asm_next(); /* past name */\n" +
  "                /* Parse type signature */\n" +
  "                type_idx = asm_parse_func_sig((int *)0);\n" +
  "                asm_funcs[imp_idx]->type_idx = type_idx;\n" +
  "                /* Record import info */\n" +
  "                asm_imports[imp_idx] = (struct AsmImport *)malloc(sizeof(struct AsmImport));\n" +
  "                asm_imports[imp_idx]->module_name = mod_name;\n" +
  "                asm_imports[imp_idx]->field_name = field_name;\n" +
  "                asm_imports[imp_idx]->func_idx = imp_idx;\n" +
  "                /* Skip to end of import form */\n" +
  "                while (asm_tok != WTOK_EOF) {\n" +
  "                    if (asm_tok == WTOK_RPAREN) { asm_next(); break; }\n" +
  "                    asm_next();\n" +
  "                }\n" +
  "                /* One more ) for the outer import */\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "\n" +
  "            } else if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"memory\") == 0) {\n" +
  "                /* (memory (export \"memory\") 512) or (memory 512) */\n" +
  "                asm_next();\n" +
  "                if (asm_tok == WTOK_LPAREN) {\n" +
  "                    /* (export \"name\") */\n" +
  "                    asm_next(); /* \"export\" */\n" +
  "                    asm_next(); /* string */\n" +
  "                    asm_mem_export_name = asm_tok_str;\n" +
  "                    asm_next(); /* ) */\n" +
  "                    if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                }\n" +
  "                if (asm_tok == WTOK_INT) {\n" +
  "                    asm_memory_pages = asm_tok_int;\n" +
  "                    asm_next();\n" +
  "                }\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "\n" +
  "            } else if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"type\") == 0) {\n" +
  "                /* (type $name (func (param ...) (result ...))) */\n" +
  "                char *tname;\n" +
  "                int tidx;\n" +
  "                asm_next(); /* $name */\n" +
  "                tname = asm_tok_str;\n" +
  "                asm_next(); /* ( */\n" +
  "                asm_next(); /* \"func\" */\n" +
  "                asm_next(); /* past \"func\" to params */\n" +
  "                tidx = asm_parse_func_sig((int *)0);\n" +
  "                /* Register named type */\n" +
  "                if (asm_ntype_names < ASM_MAX_TYPE_NAMES) {\n" +
  "                    asm_type_names[asm_ntype_names] = tname;\n" +
  "                    asm_type_indices[asm_ntype_names] = tidx;\n" +
  "                    asm_ntype_names++;\n" +
  "                }\n" +
  "                /* Skip to end: ) for func, ) for type */\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "\n" +
  "            } else if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"table\") == 0) {\n" +
  "                /* (table N funcref) */\n" +
  "                asm_next();\n" +
  "                if (asm_tok == WTOK_INT) {\n" +
  "                    asm_has_table = 1;\n" +
  "                    asm_table_size = asm_tok_int;\n" +
  "                    asm_next();\n" +
  "                }\n" +
  "                /* skip \"funcref\" and ) */\n" +
  "                if (asm_tok == WTOK_KW) asm_next();\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "\n" +
  "            } else if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"elem\") == 0) {\n" +
  "                /* (elem (i32.const 0) $fn1 $fn2 ...) */\n" +
  "                asm_next();\n" +
  "                /* Skip (i32.const 0) */\n" +
  "                if (asm_tok == WTOK_LPAREN) {\n" +
  "                    asm_next(); /* \"i32.const\" */\n" +
  "                    asm_next(); /* 0 */\n" +
  "                    asm_next(); /* ) */\n" +
  "                    if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                }\n" +
  "                /* Parse function names */\n" +
  "                asm_nelem = 0;\n" +
  "                while (asm_tok == WTOK_NAME) {\n" +
  "                    if (asm_nelem < ASM_MAX_ELEM) {\n" +
  "                        asm_elem_indices[asm_nelem] = asm_find_func(asm_tok_str);\n" +
  "                        asm_nelem++;\n" +
  "                    }\n" +
  "                    asm_next();\n" +
  "                }\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "\n" +
  "            } else if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"data\") == 0) {\n" +
  "                /* (data (i32.const N) \"string\") */\n" +
  "                int offset;\n" +
  "                struct AsmData *d;\n" +
  "                asm_next();\n" +
  "                /* (i32.const N) */\n" +
  "                if (asm_tok == WTOK_LPAREN) {\n" +
  "                    asm_next(); /* \"i32.const\" */\n" +
  "                    asm_next(); /* N */\n" +
  "                    offset = asm_tok_int;\n" +
  "                    asm_next(); /* ) */\n" +
  "                    if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                } else {\n" +
  "                    offset = 0;\n" +
  "                }\n" +
  "                /* String */\n" +
  "                if (asm_tok == WTOK_STRING) {\n" +
  "                    d = (struct AsmData *)malloc(sizeof(struct AsmData));\n" +
  "                    d->offset = offset;\n" +
  "                    d->bytes = bv_new(256);\n" +
  "                    asm_decode_string(asm_tok_str, strlen(asm_tok_str), d->bytes);\n" +
  "                    if (asm_ndata < ASM_MAX_DATA) {\n" +
  "                        asm_data_segs[asm_ndata] = d;\n" +
  "                        asm_ndata++;\n" +
  "                    }\n" +
  "                    asm_next();\n" +
  "                }\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "\n" +
  "            } else if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"global\") == 0) {\n" +
  "                /* (global $name (mut type) (type.const val)) */\n" +
  "                char *gname;\n" +
  "                int gtype;\n" +
  "                int is_mut;\n" +
  "                struct AsmGlobal *g;\n" +
  "                struct ByteVec *init;\n" +
  "                asm_next(); /* $name */\n" +
  "                gname = asm_tok_str;\n" +
  "                asm_next();\n" +
  "\n" +
  "                /* (mut type) or just type */\n" +
  "                is_mut = 0;\n" +
  "                gtype = 0x7F;\n" +
  "                if (asm_tok == WTOK_LPAREN) {\n" +
  "                    asm_next();\n" +
  "                    if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"mut\") == 0) {\n" +
  "                        is_mut = 1;\n" +
  "                        asm_next();\n" +
  "                        gtype = asm_parse_valtype(asm_tok_str);\n" +
  "                        asm_next();\n" +
  "                    } else {\n" +
  "                        gtype = asm_parse_valtype(asm_tok_str);\n" +
  "                        asm_next();\n" +
  "                    }\n" +
  "                    if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                }\n" +
  "\n" +
  "                /* Init expression: (type.const val) */\n" +
  "                init = bv_new(16);\n" +
  "                if (asm_tok == WTOK_LPAREN) {\n" +
  "                    asm_next(); /* instruction like i32.const */\n" +
  "                    if (asm_tok == WTOK_KW) {\n" +
  "                        char *init_kw;\n" +
  "                        init_kw = asm_tok_str;\n" +
  "                        asm_next(); /* value */\n" +
  "                        if (strcmp(init_kw, \"i32.const\") == 0) {\n" +
  "                            bv_push(init, 0x41);\n" +
  "                            bv_i32(init, asm_tok_int);\n" +
  "                        } else if (strcmp(init_kw, \"f64.const\") == 0) {\n" +
  "                            bv_push(init, 0x44);\n" +
  "                            if (asm_tok == WTOK_FLOAT) {\n" +
  "                                asm_emit_f64(init, asm_tok_str);\n" +
  "                            } else {\n" +
  "                                /* Integer as float */\n" +
  "                                char buf[20];\n" +
  "                                int v;\n" +
  "                                int bi;\n" +
  "                                v = asm_tok_int;\n" +
  "                                bi = 0;\n" +
  "                                if (v < 0) { buf[bi] = '-'; bi++; v = -v; }\n" +
  "                                if (v == 0) { buf[bi] = '0'; bi++; }\n" +
  "                                else {\n" +
  "                                    char tmp[12];\n" +
  "                                    int ti;\n" +
  "                                    ti = 0;\n" +
  "                                    while (v > 0) { tmp[ti] = '0' + (v % 10); ti++; v = v / 10; }\n" +
  "                                    while (ti > 0) { ti--; buf[bi] = tmp[ti]; bi++; }\n" +
  "                                }\n" +
  "                                buf[bi] = '.';\n" +
  "                                bi++;\n" +
  "                                buf[bi] = '0';\n" +
  "                                bi++;\n" +
  "                                buf[bi] = 0;\n" +
  "                                asm_emit_f64(init, buf);\n" +
  "                            }\n" +
  "                        }\n" +
  "                        asm_next(); /* past value */\n" +
  "                    }\n" +
  "                    if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                }\n" +
  "                bv_push(init, 0x0B); /* end init expr */\n" +
  "\n" +
  "                g = (struct AsmGlobal *)malloc(sizeof(struct AsmGlobal));\n" +
  "                g->name = gname;\n" +
  "                g->val_type = gtype;\n" +
  "                g->is_mutable = is_mut;\n" +
  "                g->init_expr = init;\n" +
  "                if (asm_nglobals < ASM_MAX_GLOBALS) {\n" +
  "                    asm_globals[asm_nglobals] = g;\n" +
  "                    asm_nglobals++;\n" +
  "                }\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "\n" +
  "            } else if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"func\") == 0) {\n" +
  "                /* (func $name [(export \"name\")] (param ...) (result ...) (local ...) body) */\n" +
  "                char *fname;\n" +
  "                int fidx;\n" +
  "                int type_idx;\n" +
  "                asm_next(); /* $name */\n" +
  "                fname = asm_tok_str;\n" +
  "                fidx = asm_find_func(fname);\n" +
  "                asm_next();\n" +
  "\n" +
  "                /* Check for inline (export \"name\") */\n" +
  "                if (asm_tok == WTOK_LPAREN) {\n" +
  "                    asm_save();\n" +
  "                    asm_next();\n" +
  "                    if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"export\") == 0) {\n" +
  "                        asm_next(); /* string */\n" +
  "                        asm_func_export_name = asm_tok_str;\n" +
  "                        asm_func_export_idx = fidx;\n" +
  "                        asm_next(); /* ) */\n" +
  "                        if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                    } else {\n" +
  "                        asm_restore();\n" +
  "                    }\n" +
  "                }\n" +
  "\n" +
  "                /* Parse type signature (but don't consume body) */\n" +
  "                {\n" +
  "                    int ptypes[16];\n" +
  "                    int np;\n" +
  "                    int nr;\n" +
  "                    int rt;\n" +
  "                    np = 0;\n" +
  "                    nr = 0;\n" +
  "                    rt = 0;\n" +
  "                    /* Peek at params/result without consuming them */\n" +
  "                    asm_save();\n" +
  "                    while (asm_tok == WTOK_LPAREN) {\n" +
  "                        int inner_saved_pos;\n" +
  "                        int inner_saved_tok;\n" +
  "                        char *inner_saved_str;\n" +
  "                        int inner_saved_int;\n" +
  "                        inner_saved_pos = asm_pos;\n" +
  "                        inner_saved_tok = asm_tok;\n" +
  "                        inner_saved_str = asm_tok_str;\n" +
  "                        inner_saved_int = asm_tok_int;\n" +
  "                        asm_next();\n" +
  "                        if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"param\") == 0) {\n" +
  "                            asm_next();\n" +
  "                            if (asm_tok == WTOK_NAME) asm_next();\n" +
  "                            while (asm_tok == WTOK_KW && (strcmp(asm_tok_str, \"i32\") == 0 ||\n" +
  "                                   strcmp(asm_tok_str, \"i64\") == 0 || strcmp(asm_tok_str, \"f64\") == 0)) {\n" +
  "                                if (np < ASM_MAX_PARAMS) { ptypes[np] = asm_parse_valtype(asm_tok_str); np++; }\n" +
  "                                asm_next();\n" +
  "                            }\n" +
  "                            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                        } else if (asm_tok == WTOK_KW && strcmp(asm_tok_str, \"result\") == 0) {\n" +
  "                            asm_next();\n" +
  "                            rt = asm_parse_valtype(asm_tok_str);\n" +
  "                            nr = 1;\n" +
  "                            asm_next();\n" +
  "                            if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "                        } else {\n" +
  "                            /* Not param or result — restore and stop */\n" +
  "                            asm_pos = inner_saved_pos;\n" +
  "                            asm_tok = inner_saved_tok;\n" +
  "                            asm_tok_str = inner_saved_str;\n" +
  "                            asm_tok_int = inner_saved_int;\n" +
  "                            break;\n" +
  "                        }\n" +
  "                    }\n" +
  "                    type_idx = asm_find_or_add_type(np, ptypes, nr, rt);\n" +
  "                    asm_funcs[fidx]->type_idx = type_idx;\n" +
  "                    asm_restore();\n" +
  "                }\n" +
  "\n" +
  "                /* Parse function body and encode it */\n" +
  "                asm_parse_func_body(fidx, code_sec);\n" +
  "\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "\n" +
  "            } else {\n" +
  "                /* Unknown top-level form — skip */\n" +
  "                int depth;\n" +
  "                depth = 1;\n" +
  "                while (depth > 0 && asm_tok != WTOK_EOF) {\n" +
  "                    asm_next();\n" +
  "                    if (asm_tok == WTOK_LPAREN) depth++;\n" +
  "                    if (asm_tok == WTOK_RPAREN) depth--;\n" +
  "                }\n" +
  "                if (asm_tok == WTOK_RPAREN) asm_next();\n" +
  "            }\n" +
  "        } else {\n" +
  "            asm_next(); /* skip non-( tokens at top level */\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    /* ================================================================\n" +
  "     * Encode WASM binary\n" +
  "     * ================================================================ */\n" +
  "\n" +
  "    nlocal_funcs = asm_nfuncs - asm_nimports;\n" +
  "\n" +
  "    /* Magic + version */\n" +
  "    bv_push(wasm, 0x00); bv_push(wasm, 0x61);\n" +
  "    bv_push(wasm, 0x73); bv_push(wasm, 0x6D);\n" +
  "    bv_push(wasm, 0x01); bv_push(wasm, 0x00);\n" +
  "    bv_push(wasm, 0x00); bv_push(wasm, 0x00);\n" +
  "\n" +
  "    /* Section 1: Type */\n" +
  "    bv_reset(sec);\n" +
  "    bv_u32(sec, asm_ntypes);\n" +
  "    for (i = 0; i < asm_ntypes; i++) {\n" +
  "        bv_push(sec, 0x60); /* func type */\n" +
  "        bv_u32(sec, asm_types[i]->nparams);\n" +
  "        for (j = 0; j < asm_types[i]->nparams; j++) {\n" +
  "            bv_push(sec, asm_types[i]->param_types[j]);\n" +
  "        }\n" +
  "        if (asm_types[i]->nresults > 0) {\n" +
  "            bv_u32(sec, 1);\n" +
  "            bv_push(sec, asm_types[i]->result_type);\n" +
  "        } else {\n" +
  "            bv_u32(sec, 0);\n" +
  "        }\n" +
  "    }\n" +
  "    bv_section(wasm, 1, sec);\n" +
  "\n" +
  "    /* Section 2: Import */\n" +
  "    bv_reset(sec);\n" +
  "    bv_u32(sec, asm_nimports);\n" +
  "    for (i = 0; i < asm_nimports; i++) {\n" +
  "        bv_name(sec, asm_imports[i]->module_name, strlen(asm_imports[i]->module_name));\n" +
  "        bv_name(sec, asm_imports[i]->field_name, strlen(asm_imports[i]->field_name));\n" +
  "        bv_push(sec, 0x00); /* import kind: func */\n" +
  "        bv_u32(sec, asm_funcs[i]->type_idx);\n" +
  "    }\n" +
  "    bv_section(wasm, 2, sec);\n" +
  "\n" +
  "    /* Section 3: Function */\n" +
  "    bv_reset(sec);\n" +
  "    bv_u32(sec, nlocal_funcs);\n" +
  "    for (i = asm_nimports; i < asm_nfuncs; i++) {\n" +
  "        bv_u32(sec, asm_funcs[i]->type_idx);\n" +
  "    }\n" +
  "    bv_section(wasm, 3, sec);\n" +
  "\n" +
  "    /* Section 4: Table (optional) */\n" +
  "    if (asm_has_table) {\n" +
  "        bv_reset(sec);\n" +
  "        bv_u32(sec, 1);\n" +
  "        bv_push(sec, 0x70); /* funcref */\n" +
  "        bv_push(sec, 0x00); /* limits: min only */\n" +
  "        bv_u32(sec, asm_table_size);\n" +
  "        bv_section(wasm, 4, sec);\n" +
  "    }\n" +
  "\n" +
  "    /* Section 5: Memory */\n" +
  "    bv_reset(sec);\n" +
  "    bv_u32(sec, 1);\n" +
  "    bv_push(sec, 0x00); /* limits: min only */\n" +
  "    bv_u32(sec, asm_memory_pages);\n" +
  "    bv_section(wasm, 5, sec);\n" +
  "\n" +
  "    /* Section 6: Global */\n" +
  "    if (asm_nglobals > 0) {\n" +
  "        bv_reset(sec);\n" +
  "        bv_u32(sec, asm_nglobals);\n" +
  "        for (i = 0; i < asm_nglobals; i++) {\n" +
  "            bv_push(sec, asm_globals[i]->val_type);\n" +
  "            bv_push(sec, asm_globals[i]->is_mutable ? 0x01 : 0x00);\n" +
  "            bv_append(sec, asm_globals[i]->init_expr);\n" +
  "        }\n" +
  "        bv_section(wasm, 6, sec);\n" +
  "    }\n" +
  "\n" +
  "    /* Section 7: Export */\n" +
  "    {\n" +
  "        int nexports;\n" +
  "        nexports = 0;\n" +
  "        if (asm_mem_export_name != (char *)0) nexports++;\n" +
  "        if (asm_func_export_name != (char *)0) nexports++;\n" +
  "\n" +
  "        if (nexports > 0) {\n" +
  "            bv_reset(sec);\n" +
  "            bv_u32(sec, nexports);\n" +
  "            if (asm_mem_export_name != (char *)0) {\n" +
  "                bv_name(sec, asm_mem_export_name, strlen(asm_mem_export_name));\n" +
  "                bv_push(sec, 0x02); /* memory export */\n" +
  "                bv_u32(sec, 0);\n" +
  "            }\n" +
  "            if (asm_func_export_name != (char *)0) {\n" +
  "                bv_name(sec, asm_func_export_name, strlen(asm_func_export_name));\n" +
  "                bv_push(sec, 0x00); /* func export */\n" +
  "                bv_u32(sec, asm_func_export_idx);\n" +
  "            }\n" +
  "            bv_section(wasm, 7, sec);\n" +
  "        }\n" +
  "    }\n" +
  "\n" +
  "    /* Section 9: Element (optional) */\n" +
  "    if (asm_nelem > 0) {\n" +
  "        bv_reset(sec);\n" +
  "        bv_u32(sec, 1); /* one elem segment */\n" +
  "        bv_u32(sec, 0); /* table 0, active mode */\n" +
  "        bv_push(sec, 0x41); bv_i32(sec, 0); bv_push(sec, 0x0B); /* offset = 0; end */\n" +
  "        bv_u32(sec, asm_nelem);\n" +
  "        for (i = 0; i < asm_nelem; i++) {\n" +
  "            bv_u32(sec, asm_elem_indices[i]);\n" +
  "        }\n" +
  "        bv_section(wasm, 9, sec);\n" +
  "    }\n" +
  "\n" +
  "    /* Section 10: Code */\n" +
  "    {\n" +
  "        struct ByteVec *code_full;\n" +
  "        code_full = bv_new(code_sec->len + 8);\n" +
  "        bv_u32(code_full, nlocal_funcs);\n" +
  "        bv_append(code_full, code_sec);\n" +
  "        bv_section(wasm, 10, code_full);\n" +
  "    }\n" +
  "\n" +
  "    /* Section 11: Data */\n" +
  "    if (asm_ndata > 0) {\n" +
  "        bv_reset(sec);\n" +
  "        bv_u32(sec, asm_ndata);\n" +
  "        for (i = 0; i < asm_ndata; i++) {\n" +
  "            bv_push(sec, 0x00); /* active, memory 0 */\n" +
  "            bv_push(sec, 0x41); bv_i32(sec, asm_data_segs[i]->offset); bv_push(sec, 0x0B);\n" +
  "            bv_u32(sec, asm_data_segs[i]->bytes->len);\n" +
  "            bv_append(sec, asm_data_segs[i]->bytes);\n" +
  "        }\n" +
  "        bv_section(wasm, 11, sec);\n" +
  "    }\n" +
  "\n" +
  "    /* Write binary to stdout */\n" +
  "    for (i = 0; i < wasm->len; i++) {\n" +
  "        putchar(wasm->data[i] & 0xFF);\n" +
  "    }\n" +
  "}\n" +
  "\n" +
  "/* ================================================================\n" +
  " * Entry Point\n" +
  " * ================================================================ */\n" +
  "\n" +
  "void assemble_wat(struct ByteVec *wat) {\n" +
  "    /* Initialize tokenizer */\n" +
  "    asm_src = wat->data;\n" +
  "    asm_src_len = wat->len;\n" +
  "    asm_pos = 0;\n" +
  "\n" +
  "    /* Allocate module state */\n" +
  "    asm_types = (struct AsmType **)malloc(ASM_MAX_TYPES * sizeof(void *));\n" +
  "    asm_ntypes = 0;\n" +
  "    asm_type_names = (char **)malloc(ASM_MAX_TYPE_NAMES * sizeof(char *));\n" +
  "    asm_type_indices = (int *)malloc(ASM_MAX_TYPE_NAMES * sizeof(int));\n" +
  "    asm_ntype_names = 0;\n" +
  "\n" +
  "    asm_funcs = (struct AsmFunc **)malloc(ASM_MAX_FUNCS * sizeof(void *));\n" +
  "    asm_nfuncs = 0;\n" +
  "    asm_nimports = 0;\n" +
  "    asm_imports = (struct AsmImport **)malloc(ASM_MAX_FUNCS * sizeof(void *));\n" +
  "\n" +
  "    asm_globals = (struct AsmGlobal **)malloc(ASM_MAX_GLOBALS * sizeof(void *));\n" +
  "    asm_nglobals = 0;\n" +
  "\n" +
  "    asm_data_segs = (struct AsmData **)malloc(ASM_MAX_DATA * sizeof(void *));\n" +
  "    asm_ndata = 0;\n" +
  "\n" +
  "    asm_elem_indices = (int *)malloc(ASM_MAX_ELEM * sizeof(int));\n" +
  "    asm_nelem = 0;\n" +
  "\n" +
  "    asm_local_names = (char **)malloc(ASM_MAX_LOCALS * sizeof(char *));\n" +
  "    asm_local_types = (int *)malloc(ASM_MAX_LOCALS * sizeof(int));\n" +
  "    asm_nlocals = 0;\n" +
  "\n" +
  "    asm_label_stack = (char **)malloc(ASM_MAX_LABELS * sizeof(char *));\n" +
  "    asm_label_sp = 0;\n" +
  "\n" +
  "    /* First pass: collect function names */\n" +
  "    asm_first_pass();\n" +
  "\n" +
  "    /* Reset tokenizer for second pass */\n" +
  "    asm_pos = 0;\n" +
  "\n" +
  "    /* Second pass: parse and encode */\n" +
  "    asm_second_pass();\n" +
  "}\n" +
  "";

COMPILER_SOURCE["main.c"] =
  "/* ================================================================\n" +
  " * Main\n" +
  " * ================================================================ */\n" +
  "\n" +
  "int main(void) {\n" +
  "    struct Node *prog;\n" +
  "\n" +
  "    init_kw_table();\n" +
  "    init_macros();\n" +
  "    init_includes();\n" +
  "    init_strings();\n" +
  "    init_structs();\n" +
  "    init_globals();\n" +
  "    init_func_sigs();\n" +
  "    init_fnptr_registry();\n" +
  "    init_enum_consts();\n" +
  "    init_type_aliases();\n" +
  "    init_local_tracking();\n" +
  "    init_loop_labels();\n" +
  "    init_static_map();\n" +
  "    init_gen_expr_tbl();\n" +
  "    init_gen_stmt_tbl();\n" +
  "    init_goto_labels();\n" +
  "\n" +
  "    read_source();\n" +
  "    lex_init();\n" +
  "    advance_tok();\n" +
  "    parse_current_func = (char *)0;\n" +
  "\n" +
  "    prog = parse_program();\n" +
  "    if (binary_mode) {\n" +
  "        wat_output = bv_new(65536);\n" +
  "        indent_level = 0;\n" +
  "        gen_module(prog);\n" +
  "        assemble_wat(wat_output);\n" +
  "    } else {\n" +
  "        indent_level = 0;\n" +
  "        gen_module(prog);\n" +
  "    }\n" +
  "\n" +
  "    return 0;\n" +
  "}\n" +
  "";

